var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"와아, 압축된 공간을 가르면서 단숨에 날아가는 이 기분!","JPN":"わあ……圧縮された空間を分けて、一気に飛んでいく気分って爽快！","ENG":"Whoaa! I feel like I'm flying, cutting through compressed space!","TWN":"哇，這種破開壓縮空間，一口氣飛上天的感覺！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"한 번 뛸 때마다 CRF를 왕창 잡아먹는 것 빼곤 꽤 나쁘지 않은데요, 이 슈트?","JPN":"一度ジャンプするごとに、私のCRFがわんさか削られる以外は悪くありませんね、このスーツ！","ENG":"Although it eats up a lot of my CRF every time I jump, this suit isn't too bad!","TWN":"除了每跳躍一次，我的CRF就狠狠減少以外，這件戰鬥裝備還不賴嘛？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"카린 양은 어때요?","JPN":"カリンさんはどうですか？","ENG":"How are you doing, Karin?","TWN":"卡琳你怎麼樣？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"머, 멀미가! 다이브 멀미도 안 하는 체질인데!","JPN":"よ、酔います！　ダイブでも酔わない体質なのに！","ENG":"I-I feel like I'm gonna be sick! But I don't even get motion sickness when I dive!","TWN":"我，我……我頭好暈！我的體質明明躍入時是不會暈的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하하, 그런데 어쩌나 여기서 속도 줄이면 늦을지도 모른다고요?","JPN":"ハハ、でもどうしましょう、ここでスピードを落としたら間に合わないかもしれませんよ？","ENG":"Hah hah, I could slow down, but then, we might arrive late!","TWN":"哈哈，但如果我們在這裡減速可能會來不及喔?"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그, 그럼 말 시키지 말고 계속 뛰기나 해요!","JPN":"じゃ、じゃあ話かけないで走ることに集中してください！","ENG":"Th-then stop talking to me and jump!","TWN":"那，那就別廢話，繼續跳！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"엇차!? 잘 못 뛰었다!!","JPN":"おっと！　ジャンプを間違えた！！","ENG":"Whoops?! I jumped wrong!!","TWN":"哎呀！？跳錯啦！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하, 하하. 이거 어쩌죠, 카린 양?","JPN":"ハ、ハハ。どうしましょう、カリンさん？","ENG":"Hah, hah hah. What do we do now, Karin?","TWN":"哈，哈哈。怎麼辦，卡琳？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"실수로 침식체 무리 한 가운데로 뛰어 버렸는데?","JPN":"間違えて侵食体の群れのど真ん中に飛んでしまいましたが？","ENG":"I accidentally jumped into the middle of a horde of C.O.s.","TWN":"我不小心跳進侵蝕體群中間了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"하아, 중요한 작전이니까 이번에는 진지하게 임해달라고 부탁했잖아요.","JPN":"はぁ、これは大事な作戦だから、今回だけは真剣に臨んでほしいと言ったじゃないですか。","ENG":"*Sigh* I told you to please take this operation seriously.","TWN":"哀……這次的作戰很重要，我已經拜託你認真一點。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"어쩔 수 없죠. 그대로 길을 열 테니까, 멈추지 말고 뛰어요. 시영 씨.","JPN":"仕方ないですね。道を開きますから、このまま止まらずに走ってください、シノンさん。","ENG":"Well, all right. I'll make way, so just keep jumping, Shiyoung.","TWN":"沒辦法，我來開路吧，別停，繼續跳，時雨。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"디바이스 세트 온.","JPN":"デバイスセットON。","ENG":"Device set on.","TWN":"設備開啟。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"파츠 교체, 전술 무장 3번, <color=#ffd34c>로드 메이커</color>.","JPN":"パーツ交換、戦術武装3番、<color=#ffd34c>ロードメーカー</color>。","ENG":"Exchanging parts, Tactical Gear No. 3, <color=#ffd34c>Road Maker</color>.","TWN":"更換零件，3號戰術裝備<color=#ffd34c>開路者</color>。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"치, 침식체 뿐만 아니라 주변 지형까지 날려버렸어.","JPN":"し、侵食体だけじゃなくて、周辺の地形まで吹っ飛ばした。","ENG":"Y-you didn't just get rid of the C.O.s; you cleared out the surrounding landscape.","TWN":"不僅是侵蝕體，連周圍的也都一塊清掉了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"원래라면 하나하나가 도시를 파괴할 정도의 침식체들인데.","JPN":"あの一体一体が都市破壊レベルの侵食体だっていうのに。","ENG":"Normally, each and every one of the C.O.s here are capable of destroying a city.","TWN":"明明每個都是足以破壞城市的等級的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"어서 가요, 시영 씨. 여기서 주저할 시간이 없어요.","JPN":"早く行きましょう、シノンさん。ここでぐずぐずしている時間はありません。","ENG":"Let's go, Shiyoung. We can't waste any more time.","TWN":"快走吧，時雨，沒有時間磨蹭了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"어라, 카린 양?","JPN":"あれ、カリンさん？","ENG":"Huh? Karin?","TWN":"呃，卡琳？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"코피…… 나는데요……?","JPN":"鼻血が……出ていますよ……？","ENG":"Your nose... It's bleeding…?","TWN":"你……流鼻血了……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이 정도는 괜찮아요.","JPN":"これくらい平気です。","ENG":"I'm fine.","TWN":"這不算什麼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"신경 쓰지 말고 계속 가요, 시영 씨.","JPN":"気にしないで進んでください、シノンさん。","ENG":"Don't worry about me. Keep going, Shiyoung.","TWN":"別擔心我，繼續前進，時雨。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"아, 이제 정말 나는 카린 양이 나아가는 걸 붙잡을 수도 없고, 붙잡아서도 안 되는구나.","JPN":"ああ、もう本当にカリンさんが突き進んでいくのを引き留められないし、引き留めちゃいけないんだ。","ENG":"Oh, I guess I can't and shouldn't stop Karin from moving forward.","TWN":"現在的我真的無法阻攔她，也不能阻攔她。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 적어도.","JPN":"ならば、せめて。","ENG":"Then, at least...","TWN":"那麼至少。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"적어도 친구가 안심하고 나아갈 수 있도록 등 뒤를 지켜줄 수밖에 없겠네.","JPN":"せめて友が安心して突き進めるように、サポートするしかないよね。","ENG":"The least I can do is watch her back so that she can move forward without having to worry.","TWN":"至少讓朋友能夠安心前進，做好她的後盾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};